	.TITLE	SOUND;	--------------------------------------;		(C) 1985 - Daniel Roux;	--------------------------------------	.PROC	M680002	.RADIX	10.	.HEX	.REF	DRIVERS	.REF	LIB	.REF	SM8	.REF	BIOS	.REF	NTREL	.REF	GESMEM	.REF	FOS	.REF	GRA	.REF	DBOX	.REF	LIST; Constantes; ----------LWRBUF	=	5000		; lg buffer en critureLRDBUF	=	5000		; lg buffer en lectureLBUFILE	=	32		; lg max d'un nom de fichier; Variables; ---------	.LOC	0OCHDBOX:.BLKB	2		; canal module DBOXOCHLIST:.BLKB	2		; canal module LISTONDMIDI:.BLKB	2		; no du driver MIDIOPDDIS:	.BLKB	4		; ^descripteur de la fentreOQXDOT:	.BLKB	4		; adresse de GRA_QXDOTOFLAGS:	.BLKB	1		; flags divers BWAIT32=  0			;  attend 32 timbres	.EVENONAMEI:	.BLKB	LBUFILE		; nom de fichier en entreONAMEO:	.BLKB	LBUFILE		; nom de fichier en sortieOWRBUF:	.BLKB	LWRBUF		; buffer en critureORDBUF:	.BLKB	LRDBUF		; buffer en lectureOLWAIT:	.BLKB	4		; lg reueLGVAR:; Programme; ---------	.LOC	0START:;;?	.W	LIB,?OPELIB	LOAD.W	D3,#3	.W	LIB,?MOUSE	CALL	NORMMOUSE	LOAD.L	D4,#LGVAR	LOAD.W	D1,#MTYPCP	.W	GESMEM,?GETMEM	; demande mmoire pour var.	JUMP,NE ERFAT	LOAD.L	A6,A4		; A6 <-- ^variables10$:	CLR.B	(A4+)		; met TOUTES les variables  zro	DEC.W	D4	JUMP,NE 10$	.W	LIB,?GCHDIS	; D6 <-- canal cran	LOAD.W	D3,#TYPWDO	; D3 <-- type fentre cran	LOAD.L	D4,#4		; D4 <-- longueur demande	LOAD.L	A4,#(A6)+OPDDIS	; A4 <-- ^buffer	.W	FOS,?RSTATUS	; demande le ^rel !	JUMP,NE ERFAT	LOAD.L	A0,(A6)+OPDDIS	; A0 <-- ^descripteur de la fentre <<PREMANANT>>	LOAD.W	D3,#GRA_QXDOT	.W	LIB_GETAD	JUMP,NE ERFAT	LOAD.L	(A6)+OQXDOT,A3	LOAD.L	A3,#R16"NMDBOX	LOAD.W	D3,#DBOX_FIRST	.W	LIB_OPEN	JUMP,NE ERFAT	LOAD.W	(A6)+OCHDBOX,D1	LOAD.L	A3,#R16"NMLIST	LOAD.W	D3,#LIST_FIRST	.W	LIB_OPEN	JUMP,NE ERFAT	LOAD.W	(A6)+OCHLIST,D1CALL CLOMIDI	CALL	OPEMIDI	JUMP,NE ERFATLOOP:	.W	LIB,?AFTIM	.B	CR	.ASCIZ	"(W)ait, (END) ? "	.EVEN	.W	LIB,?GETCAR	.W	LIB,?MINMAJ	.W	LIB,?AFCODE	COMP.W	D3,#'W	JUMP,EQ 50$	COMP.W	D3,#END	JUMP,EQ FINI	JUMP	BIP50$:	CALL	WAIT32;;?	JUMP,NE ERROR	JUMP	LOOPBIP:				; erreur =>	LOAD.B	D3,#BIPLIT	.W	LIB,?BEEP	; p'tit bruit	JUMP	LOOPERROR:	PUSH.W	D7	CALL	NORMMOUSE	; remet la flche	LOAD.W	D3,#BIPERR	.W	LIB,?BEEP	; fait un bruit	POP.W	D7	LOAD.W	D2,#2^BDBSAV	; D2 <-- mode	.W	DBOX_MERROR	; affiche l'erreur	JUMP	LOOPFINI:	CALL	CLOMIDIERFAT:	LOAD.W	D1,(A6)+OCHDBOX	.W	LIB_CLOSE	LOAD.W	D1,(A6)+OCHLIST	.W	LIB_CLOSE;;?	.W	LIB,?CLOLIB;;?	.W	FOS,?STOPEXIT;--------\\; WAIT32  >;========/; Attend l'envoi de 32 timbres.; in	-; out	A4.L	^32 X 128 bytes;	D7.W	erreur; mod	D7.W, A4.LWAIT32:	PUSHM.L	D2..D5,A3,A510$:	.W	LIB,?AFCR	LOAD.L	A4,#R16"TXDATA;	.W	LIB,?AFTIM;	.ASCIZ	"G=";	.EVEN;	.W	LIB,?GETDEC;	COMP.W	D3,#END;	JUMP,EQ 90$LOAD.W D4,#2	LOAD.B	D0,D4;	.W	LIB,?AFTIM;	.ASCIZ	"H=";	.EVEN;	.W	LIB,?GETDEC;	COMP.W	D3,#END;	JUMP,EQ 90$LOAD.W D4,#0	SL.B	D0,#2	OR.B	D4,D0	LOAD.B	(A4)+5,D4	.W	LIB,?AFTIM	.ASCIZ	"P="	.EVEN	.W	LIB,?GETDEC	COMP.W	D3,#END	JUMP,EQ 90$	LOAD.B	(A4)+6,D4	.W	LIB,?AFTIM	.ASCIZ	"V="	.EVEN	.W	LIB,?GETDEC	COMP.W	D3,#END	JUMP,EQ 90$	LOAD.B	(A4)+7,D4	LOAD.L	A4,#R16"TXDATA	LOAD.L	D5,#LXDATA	LOAD.W	D2,(A6)+ONDMIDI	.W	BIOS,?DWRITE	JUMP 10$90$:	POPM.L	D2..D5,A3,A5	TEST.W	D7		; retour EQ/NE	RETTXDATA:	.B	0,7	.B	H'F0	.B	H'43	.B	H'10	.B	8		; G H	.B	76		; P	.B	11	.B	H'F7LXDATA	=	.-TXDATA	.EVEN;;;;;;;;;;;;;;;    WAIT    ;;;;;;;;;;;;;;;NWAIT32:.ASCIZ	"MIDI_WAIT32"	.EVENPWAIT32:	LOAD.L	A4,#(A6)+ORDBUF	LOAD.L	D5,#H'1017	LOAD.W	D2,(A6)+ONDMIDI	.W	BIOS,?DREAD	LOAD.L	(A6)+OLWAIT,D5	TCLR.B	(A6)+OFLAGS:#BWAIT32	.W	NTREL,?ABORT;----------\\; WAITMOUSE >;==========/; Met la souris en attente (sablier).; in	-; out	-; mod	-WAITMOUSE:	PUSHM.L	D4,D7	CLR.W	D4	.W	LIB,?WAITMOUSE	POPM.L	D4,D7	RET;----------\\; NORMMOUSE >;==========/; Remet la flche de la souris.; in	-; out	-; mod	-NORMMOUSE:	PUSHM.L	D4,D7	LOAD.W	D4,#1	.W	LIB,?WAITMOUSE	POPM.L	D4,D7	RET;--------\\; COMMAND >;========/; Envoie une commande  MIDI.; in	A4.L	^commande; out	D7.W	erreur; mod	D7.WCOMMAND:	PUSHM.L	D1,D2	LOAD.W	D1,#TYPIO	; D1 <-- type	LOAD.W	D2,(A6)+ONDMIDI	.W	BIOS,?DCOMMAND	POPM.L	D1,D2	TEST.W	D7		; retour EQ/NE	RET;---------\\; STOPMIDI >;=========/; Stoppe compltement MIDI.; in	-; out	-; mod	D7.WSTOPMIDI:	PUSH.L	D2	LOAD.W	D2,(A6)+ONDMIDI	.W	BIOS,?DAVOTR	; avort lecture/criture	POP.L	D2	RET;--------\\; OPEMIDI >;========/; Ouvre le driver MIDI.; in	-; out	D7.W	erreur; mod	D7.WOPEMIDI:	PUSHM.L	D2,D3,A2..A4	LOAD.L	A3,#R16"LMIDI	; A3 <-- ^nom logique	LOAD.L	A4,#R16"PMIDI	; A4 <-- ^nom physique	LOAD.L	A2,#0		; A2 <-- ^paramtres	CLR.W	D3		; D3 <-- pour tous	.W	FOS,?INSTALL	; install le driver	JUMP,NE	90$	LOAD.L	A3,#R16"DMIDI	.W	FOS,?UNAMDRIV	; D2 <-- numro de driver	JUMP,NE	90$	LOAD.W	(A6)+ONDMIDI,D2	90$:	POPM.L	D2,D3,A2..A4	TEST.W	D7		; retour EQ/NE	RET;--------\\; CLOMIDI >;========/; Ferme le driver MIDI.; in	-; out	-; mod	D7.WCLOMIDI:	PUSHM.L	D3,A3	LOAD.L	A3,#R16"LMIDI	; A3 <-- ^nom logique	CLR.W	D3		; D3 <-- pour tous	.W	FOS,?DEINSTALL	; dinstall le driver	POPM.L	D3,A3	RET; Tables; ------DOKF0:	LOAD.W	D3,#F0	RETDOKF1:	LOAD.W	D3,#F1	RETDOKF4:	LOAD.W	D3,#F4	RETDOKF7:	LOAD.W	D3,#F7	RETDOKF10:	LOAD.W	D3,#F10	RETDOKF13:	LOAD.W	D3,#F13	RETDOKMGR:	LOAD.W	D3,#KEYMGR	RET; Textes; ------NMDBOX:	.ASCIZ	"DBOX"NMLIST:	.ASCIZ	"LIST"LMIDI:	.ASCIZ	"#MIDI:"PMIDI:	.ASCIZ	"$MIDI_0"DMIDI:	.ASCIZ	"MIDI_0"CMSYNC:	.ASCIZ	"S"		; commande de synchronisationTXEXT:	.ASCIZ	".midi"	.EVEN	.END	START